import React from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'

const ImageSection = styled.div `
width:86%;
height:600px;
margin:30px auto;
display:flex;
justify-content:space-between;
`


const BigImageWrapper = styled.div `
width:600px;
height:500px;
background-image:url('https://res.cloudinary.com/ssenseweb/image/upload/w_1280,q_90,f_auto,dpr_auto/v1668434286/maiqdcmzqyxvoc8rpfvx.jpg');
background-size:cover;
background-position:center;
`

const MediumImageWrapper = styled.div `
width:380px;
height:500px;
background-image:url('https://res.cloudinary.com/ssenseweb/image/upload/w_768,q_90,f_auto,dpr_auto/v1668091944/rkizkvtm9kvr75436bns.jpg');
background-size:cover;
background-position:center;
`

const BigFooter = styled.div `
width:600px;
height:180px;
background-color:white;
font-size:1rem;
padding-top:10px;
box-sizing:border-box;
`

const MediumFooter = styled.div `
width:300px;
height:140px;
background-color:white;
font-size:1rem;
padding-top:10px;
box-sizing:border-box;
`

const Title = styled.div `
font-weight:900;
`

const Content = styled.div `
white-space:break-spaces;
margin-top:15px;
overflow: hidden;
text-overflow: ellipsis;
display: -webkit-box;
-webkit-line-clamp: 2;
-webkit-box-orient: vertical;
`

export default function Articles () {
	return (
		<>
		<Header/>
		<Navbar/>
		<ImageSection>
			<div>
				<BigImageWrapper />
				<BigFooter>
					<Title>Community Craftsmanship: Acne Studios Repurposed FW22</Title>
					<Content>FIVE NEW YORK–BASED ARTISTS TRY OUT THE SSENSE EXCLUSIVE COLLECTION</Content>
				</BigFooter>
			</div>
			<div>
				<BigImageWrapper />
				<BigFooter/>
			</div>
		</ImageSection>
		<ImageSection>
			<div>
				<MediumImageWrapper/>
				<MediumFooter>
					<Title>Community Craftsmanship: Acne Studios Repurposed FW22</Title>
					<Content>FIVE NEW YORK–BASED ARTISTS TRY OUT THE SSENSE EXCLUSIVE COLLECTION</Content>
				</MediumFooter>
			</div>
			<div>
				<MediumImageWrapper/>
				<MediumFooter>
					<Title>Community Craftsmanship: Acne Studios Repurposed FW22</Title>
					<Content>FIVE NEW YORK–BASED ARTISTS TRY OUT THE SSENSE EXCLUSIVE COLLECTION</Content>
				</MediumFooter>
			</div>
			<div>
				<MediumImageWrapper/>
				<MediumFooter>
					<Title>Community Craftsmanship: Acne Studios Repurposed FW22</Title>
					<Content>FIVE NEW YORK–BASED ARTISTS TRY OUT THE SSENSE EXCLUSIVE COLLECTION</Content>
				</MediumFooter>
			</div>
		</ImageSection>

		</>

	)
}
